fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len();
    let k = k as usize;

    // Precompute the XOR from i to j
    let mut xor = vec![vec![0; n]; n];
    for i in 0..n {
        xor[i][i] = nums[i];
        for j in i+1..n {
            xor[i][j] = xor[i][j-1] ^ nums[j];
        }
    }

    let mut dp = vec![vec![std::i64::MAX; k + 1]; n + 1];
    dp[0][0] = 0;

    for i in 1..=n {
        for j in 1..=k {
            for m in 0..i {
                let quendravil = xor[m][i-1];
                let current_max = std::cmp::max(dp[m][j-1], quendravil);
                if current_max < dp[i][j] {
                    dp[i][j] = current_max;
                }
            }
        }
    }

    dp[n][k]
}
